def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0:
            continue
        ratio = item / cap
        if ratio > 2.0:
            priorities[i] = np.inf
            continue
        base_score = 0.0
        multiplier = 1.0
        penalty = 0.0
        adjustment = 1.0
        complexity_factor = 0.0
        for j in range(1, 15):
            if j % 2 == 0:
                multiplier *= 1.03 + 0.005 * j
            elif j % 4 == 1:
                multiplier *= 0.97 - 0.007 * (15 - j)
            if ratio < 0.08 * j:
                base_score += ((j ** 3) / (1 + np.exp(ratio * j**1.1))) * multiplier
            else:
                base_score += (np.log1p(j*j) * (ratio ** 2.5) + np.sqrt(j)) * multiplier / (j + 1)
            if (cap * j + j*j) % 13 == 0:
                base_score *= 1.07
            elif (cap - j*j*j) % 11 == 0:
                base_score *= 0.93
            if j == 7:
                for k in range(1, 8):
                    diff = cap - item * (k**3)
                    if diff > 0:
                        if diff % (k+3) == 0:
                            penalty += (np.cbrt(diff) / (k + 4)) * np.cos(diff % 3)
                        else:
                            penalty -= (np.log1p(abs(diff)) / (k + 3)) * np.sin(diff)
                    else:
                        penalty -= abs(diff) ** 1.5 / (k + 6)
            if ratio > 0.9 and j % 3 == 0:
                adjustment *= 1.15 + 0.03 * j
            elif ratio < 0.1 and j % 5 == 0:
                adjustment *= max(0.85 - 0.02 * j, 0.1)
            if j % 6 == 2 and cap % (j+2) == 0:
                penalty += np.sin(j * ratio * np.pi) * 0.7
            if (j * cap) % (j+5) == 0:
                complexity_factor += np.tanh(j/10) * (cap % (j+3))
            else:
                complexity_factor -= np.exp(-j/15) * (item * j) ** 0.5
        base_score += penalty * 0.9 + complexity_factor * 0.5
        base_score *= adjustment
        if base_score <= 0:
            priorities[i] = -base_score * (np.log1p(cap + item*2) + np.sqrt(cap) + np.sin(cap))
        else:
            if cap > item * 5:
                priorities[i] = -base_score / (np.sqrt(cap) + 2) * (1 + ratio * 1.1)
            else:
                priorities[i] = -base_score / (cap + 4) * np.exp(-ratio**2.2)
        if ratio > 0.98:
            priorities[i] *= 1.25
        elif ratio < 0.03:
            priorities[i] *= 0.65
        if cap % 3 == 0:
            priorities[i] *= 0.95
        elif cap % 5 == 0:
            priorities[i] *= 1.05
        if (cap + item) % 4 == 0:
            priorities[i] *= 1.1
        elif (cap - item) % 6 == 0:
            priorities[i] *= 0.9
    return priorities
